import fs from "fs";
import path from "path";
import { fileURLToPath } from "url";

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const OUT_DIR = path.join(__dirname, "..", "src", "data", "exam-sets");

const T1 = "Konsep dan Proses Pengurusan";
const T2 = "Fungsi Pengurusan dan Kepimpinan";
const T3 = "Perancangan Pendidikan";
