const T10 = "Sekolah dan Masa Depan";

function q(setNum, num, topicId, topicName, difficulty, cognitiveLevel, stem, opts, correctLetter, explanation, moduleRef) {
  const letters = ["A", "B", "C", "D"];
  return {
    id: `set${setNum}-q${String(num).padStart(2, "0")}`,
    topicId,
    topicName,
    difficulty,
    cognitiveLevel,
    stem,
    options: opts.map((text, i) => ({ id: letters[i], text })),
    correctOptionId: correctLetter,
    explanation,
    moduleRef,
  };
}

