// Tulis fail JSON
const allSets = [set1, set2, set3, set4, set5];
fs.mkdirSync(OUT_DIR, { recursive: true });

const stems = new Set();
for (const [i, questions] of allSets.entries()) {
  const setNum = i + 1;
  if (questions.length !== 40) {
    throw new Error(`Set ${setNum} mempunyai ${questions.length} soalan, dijangka 40.`);
  }
  for (const question of questions) {
    if (stems.has(question.stem)) {
      throw new Error(`Stem pendua ditemui: "${question.stem}"`);
    }
    stems.add(question.stem);
  }
  const topicCounts = {};
  for (const question of questions) {
    topicCounts[question.topicId] = (topicCounts[question.topicId] || 0) + 1;
  }
  for (let t = 1; t <= 10; t++) {
    if (topicCounts[t] !== 4) {
      throw new Error(`Set ${setNum} topik ${t} mempunyai ${topicCounts[t] || 0} soalan, dijangka 4.`);
    }
  }
  const diff = { easy: 0, moderate: 0, hard: 0 };
  for (const question of questions) diff[question.difficulty]++;
  if (diff.easy !== 16 || diff.moderate !== 16 || diff.hard !== 8) {
    throw new Error(`Set ${setNum} campuran kesukaran: mudah=${diff.easy}, sederhana=${diff.moderate}, sukar=${diff.hard}`);
  }
  const outPath = path.join(OUT_DIR, `set-${setNum}.json`);
  fs.writeFileSync(outPath, JSON.stringify(questions, null, 2), "utf8");
  console.log(`Ditulis ${outPath} (${questions.length} soalan)`);
}

console.log(`\nJumlah: ${stems.size} soalan unik merentas 5 set.`);
